import{_ as e,o as i,c as r,a2 as a}from"./chunks/framework.OWFDNrRT.js";const u=JSON.parse('{"title":"ADR-004: Registry Model","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-004-registry-model.md","filePath":"adr/ADR-004-registry-model.md","lastUpdated":1773460793000}'),d={name:"adr/ADR-004-registry-model.md"};function o(s,t,n,l,c,h){return i(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="adr-004-registry-model" tabindex="-1">ADR-004: Registry Model <a class="header-anchor" href="#adr-004-registry-model" aria-label="Permalink to &quot;ADR-004: Registry Model&quot;">​</a></h1><p><strong>Status</strong>: Accepted <strong>Date</strong>: 2026-03-09 <strong>Deciders</strong>: kooshapari</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Without a central registration model, agents will scatter content definitions across arbitrary files and hardcode IDs into engine glue. This creates unmaintainable spaghetti.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Everything goes through registries. Agents add or override entries in registries. They do not just &quot;edit the game.&quot;</p><h3 id="registry-domains" tabindex="-1">Registry Domains <a class="header-anchor" href="#registry-domains" aria-label="Permalink to &quot;Registry Domains&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Registry</th><th>Contents</th></tr></thead><tbody><tr><td>Units</td><td>Unit definitions with role, stats, behavior, visuals</td></tr><tr><td>Buildings</td><td>Building definitions with role, cost, tech requirements</td></tr><tr><td>Weapons</td><td>Weapon definitions with damage model, projectile type</td></tr><tr><td>Projectiles</td><td>Projectile definitions with VFX, speed, behavior</td></tr><tr><td>Effects</td><td>Visual/audio effects</td></tr><tr><td>Audio Packs</td><td>Sound replacement sets</td></tr><tr><td>UI Skins</td><td>UI theme definitions</td></tr><tr><td>Doctrines</td><td>Faction-level gameplay modifiers</td></tr><tr><td>Factions</td><td>Faction definitions with roster, economy, visuals</td></tr><tr><td>Wave Templates</td><td>Enemy wave composition and timing</td></tr><tr><td>Behaviors</td><td>AI behavior tags and rules</td></tr><tr><td>Scenario Scripts</td><td>Mission events and triggers</td></tr><tr><td>Tech Nodes</td><td>Research tree entries</td></tr><tr><td>Localization</td><td>String bundles per language</td></tr></tbody></table><h3 id="registry-contract" tabindex="-1">Registry Contract <a class="header-anchor" href="#registry-contract" aria-label="Permalink to &quot;Registry Contract&quot;">​</a></h3><p>Each registry entry has:</p><ul><li>Unique string ID (namespaced: <code>pack_id:entry_id</code>)</li><li>Schema-validated data</li><li>Override priority (base &lt; framework &lt; domain &lt; pack)</li><li>Source pack reference</li><li>Validation status</li></ul><h3 id="override-model" tabindex="-1">Override Model <a class="header-anchor" href="#override-model" aria-label="Permalink to &quot;Override Model&quot;">​</a></h3><p>Layered content overrides:</p><ol><li>Base game defaults (discovered via introspection)</li><li>Framework defaults</li><li>Domain plugin additions</li><li>Pack-level overrides</li></ol><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><ul><li>Composability: multiple packs can contribute to same registry</li><li>Diffability: registry state is inspectable</li><li>Testability: mock registries for testing</li><li>Pack install/uninstall: registry entries are scoped to packs</li><li>Validation: duplicate ID detection, missing reference detection</li><li>Compatibility: conflict detection when packs override same entries</li></ul>',16)])])}const m=e(d,[["render",o]]);export{u as __pageData,m as default};
